**AuthManager.kt:**
```kotlin
import com.auth0.android.Auth0
import com.auth0.android.authentication.AuthenticationAPIClient
import com.auth0.android.authentication.storage.SecureCredentialsManager
import com.auth0.android.authentication.storage.SharedPreferencesStorage
import com.auth0.android.callback.Callback
import com.auth0.android.provider.WebAuthProvider
import com.auth0.android.result.Credentials
import com.auth0.android.result.SSOCredentials
import com.auth0.android.authentication.AuthenticationException

class AuthManager(context: Context) {
    private val account = Auth0.getInstance(context)
    private val storage = SharedPreferencesStorage(context)
    private val credentialsManager = SecureCredentialsManager(account, context, storage)

    fun getCredentials(callback: Callback<Credentials, com.auth0.android.authentication.storage.CredentialsManagerException>) {
        credentialsManager.getCredentials(callback)
    }

    fun secondsUntilSsoExpiry(sso: SSOCredentials): Int {
        return sso.expiresIn
    }

    fun logout() {
        credentialsManager.clearCredentials()
    }
}
```
